results = _input.first().json.get('results', [])

message = "✅ <b>Lead Enrichment Complete</b>\n\n"

for i, res in enumerate(results):
    status_icon = "🎯" if res.get('status') == 'success' else "⚠️"
    message += f"{status_icon} <b>{i+1}. {res.get('name')}</b>\n"
    if res.get('phone'):
        message += f"   📞 <code>{res.get('phone')}</code>\n"
    if res.get('email') and res.get('email') != 'None':
        message += f"   📧 {res.get('email')}\n"
    if res.get('contactPage'):
        message += f"   🔗 <a href='{res.get('contactPage')}'>Contact Page</a>\n"
    elif res.get('website') and res.get('website') != 'None':
        message += f"   🌐 <a href='{res.get('website')}'>Website</a>\n"
    message += "\n"

if not results:
    message += "No results gathered in this batch."

return [{ "json": { "message": message } }]
